// frontend/src/components/clients/ClientDashboard.js
import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import api from '../../services/api';
import { useAuth } from '../../contexts/AuthContext';
import './ClientDashboard.css';

const ClientDashboard = () => {
    const { user } = useAuth();
    const [jobs, setJobs] = useState({
        posted: [],
        assigned: [],
        in_progress: [],
        completed: [],
        cancelled: []
    });
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [activeTab, setActiveTab] = useState('assigned');

    // Rating modal states
    const [showRatingModal, setShowRatingModal] = useState(false);
    const [currentJobForRating, setCurrentJobForRating] = useState(null);
    const [ratingData, setRatingData] = useState({
        rating: 5,
        review: ''
    });

    useEffect(() => {
        loadClientJobs();
    }, []);

    const loadClientJobs = async () => {
        setLoading(true);
        try {
            const response = await api.get('/client/jobs');
            if (response.data.success) {
                const allJobs = response.data.data;

                setJobs({
                    posted: allJobs.filter(job => job.status === 'posted'),
                    assigned: allJobs.filter(job => job.status === 'assigned'),
                    in_progress: allJobs.filter(job => job.status === 'in_progress'),
                    completed: allJobs.filter(job => job.status === 'completed'),
                    cancelled: allJobs.filter(job => job.status === 'cancelled')
                });
            } else {
                setError('Failed to load jobs');
            }
        } catch (error) {
            console.error('Error loading client jobs:', error);
            setError('Network error. Please try again.');
        } finally {
            setLoading(false);
        }
    };

    const handleStartJob = async (jobId) => {
        if (!window.confirm('Start this job? The worker will be notified that work has begun.')) {
            return;
        }

        try {
            const response = await api.post(`/jobs/${jobId}/start`);
            if (response.data.success) {
                alert('✅ Job started! The worker has been notified.');
                loadClientJobs();
            }
        } catch (error) {
            console.error('Error starting job:', error);
            alert('Failed to start job. Please try again.');
        }
    };

    const handleCompleteClick = (job) => {
        setCurrentJobForRating(job);
        setShowRatingModal(true);
    };

    const handleCompleteJob = async () => {
        if (!currentJobForRating) return;

        try {
            const response = await api.post(`/jobs/${currentJobForRating.id}/complete`, {
                rating: ratingData.rating,
                review: ratingData.review
            });

            if (response.data.success) {
                alert(`✅ Job completed! Worker rating updated to ${response.data.data.worker_rating.toFixed(1)}⭐`);
                setShowRatingModal(false);
                setRatingData({ rating: 5, review: '' });
                setCurrentJobForRating(null);
                loadClientJobs();
            }
        } catch (error) {
            console.error('Error completing job:', error);
            alert('Failed to complete job. Please try again.');
        }
    };

    const handleCancelJob = async (jobId) => {
        if (!window.confirm('Cancel this job? This cannot be undone.')) {
            return;
        }

        try {
            const response = await api.post(`/jobs/${jobId}/cancel`);
            if (response.data.success) {
                alert('Job cancelled.');
                loadClientJobs();
            }
        } catch (error) {
            console.error('Error cancelling job:', error);
            alert('Failed to cancel job. Please try again.');
        }
    };

    const formatDate = (dateString) => {
        const date = new Date(dateString);
        return date.toLocaleDateString('en-ZA', {
            day: 'numeric',
            month: 'short',
            year: 'numeric'
        });
    };

    const renderJobs = (jobList, status) => {
        if (jobList.length === 0) {
            return (
                <div className="empty-state">
                    <p>No {status} jobs</p>
                    <Link to="/jobs/post" className="btn-primary">Post a Job</Link>
                </div>
            );
        }

        return jobList.map(job => (
            <div key={job.id} className={`job-card status-${job.status}`}>
                <div className="job-header">
                    <h3>{job.title}</h3>
                    <span className="job-status-badge">{job.status}</span>
                </div>

                <div className="job-details">
                    <p className="job-description">{job.description}</p>

                    <div className="job-meta">
                        <span>📍 {job.township}</span>
                        <span>💰 R{job.budget_min} - R{job.budget_max}</span>
                        <span>📅 Posted {formatDate(job.created_at)}</span>
                    </div>

                    {job.assigned_worker && (
                        <div className="worker-info">
                            <h4>Worker:</h4>
                            <div className="worker-details">
                                <span className="worker-name">👤 {job.assigned_worker.name}</span>
                                <span className="worker-rating">⭐ {job.assigned_worker.rating?.toFixed(1) || 'New'}</span>
                                <span className="worker-phone">📱 {job.assigned_worker.phone}</span>
                                <Link to={`/workers/${job.assigned_worker.id}`} className="worker-profile-link">
                                    View Profile →
                                </Link>
                            </div>
                        </div>
                    )}

                    <div className="job-actions">
                        <Link to={`/jobs/${job.id}`} className="btn-view">
                            View Details
                        </Link>

                        {job.status === 'assigned' && (
                            <>
                                <button 
                                    className="btn-start"
                                    onClick={() => handleStartJob(job.id)}
                                >
                                    ▶️ Start Job
                                </button>
                                <button 
                                    className="btn-cancel"
                                    onClick={() => handleCancelJob(job.id)}
                                >
                                    ✕ Cancel
                                </button>
                            </>
                        )}

                        {job.status === 'in_progress' && (
                            <>
                                <button 
                                    className="btn-complete"
                                    onClick={() => handleCompleteClick(job)}
                                >
                                    ✅ Complete Job
                                </button>
                                <button 
                                    className="btn-cancel"
                                    onClick={() => handleCancelJob(job.id)}
                                >
                                    ✕ Cancel
                                </button>
                            </>
                        )}

                        {job.status === 'completed' && (
                            <button className="btn-review">
                                ⭐ Leave Review
                            </button>
                        )}
                    </div>
                </div>
            </div>
        ));
    };

    if (loading) {
        return <div className="loading-spinner">Loading your jobs...</div>;
    }

    return (
        <div className="client-dashboard">
            <div className="dashboard-header">
                <h1>My Jobs Dashboard</h1>
                <Link to="/jobs/post" className="btn-primary">
                    + Post New Job
                </Link>
            </div>

            {error && <div className="error-message">{error}</div>}

            {/* Stats Cards */}
            <div className="stats-grid">
                <div className="stat-card">
                    <span className="stat-value">{jobs.posted.length}</span>
                    <span className="stat-label">Open Jobs</span>
                </div>
                <div className="stat-card">
                    <span className="stat-value">{jobs.assigned.length}</span>
                    <span className="stat-label">Assigned</span>
                </div>
                <div className="stat-card">
                    <span className="stat-value">{jobs.in_progress.length}</span>
                    <span className="stat-label">In Progress</span>
                </div>
                <div className="stat-card">
                    <span className="stat-value">{jobs.completed.length}</span>
                    <span className="stat-label">Completed</span>
                </div>
            </div>

            {/* Tab Navigation */}
            <div className="tab-navigation">
                <button 
                    className={`tab-btn ${activeTab === 'assigned' ? 'active' : ''}`}
                    onClick={() => setActiveTab('assigned')}
                >
                    To Start ({jobs.assigned.length})
                </button>
                <button 
                    className={`tab-btn ${activeTab === 'in_progress' ? 'active' : ''}`}
                    onClick={() => setActiveTab('in_progress')}
                >
                    In Progress ({jobs.in_progress.length})
                </button>
                <button 
                    className={`tab-btn ${activeTab === 'posted' ? 'active' : ''}`}
                    onClick={() => setActiveTab('posted')}
                >
                    Open ({jobs.posted.length})
                </button>
                <button 
                    className={`tab-btn ${activeTab === 'completed' ? 'active' : ''}`}
                    onClick={() => setActiveTab('completed')}
                >
                    Completed ({jobs.completed.length})
                </button>
            </div>

            {/* Jobs List */}
            <div className="jobs-list">
                {activeTab === 'assigned' && renderJobs(jobs.assigned, 'assigned')}
                {activeTab === 'in_progress' && renderJobs(jobs.in_progress, 'in progress')}
                {activeTab === 'posted' && renderJobs(jobs.posted, 'open')}
                {activeTab === 'completed' && renderJobs(jobs.completed, 'completed')}
            </div>

            {/* Rating Modal */}
            {showRatingModal && currentJobForRating && (
                <div className="modal-overlay">
                    <div className="rating-modal">
                        <h2>Rate the Worker</h2>
                        <p>How was {currentJobForRating.assigned_worker?.name}'s work?</p>

                        <div className="rating-stars">
                            {[1, 2, 3, 4, 5].map(star => (
                                <button
                                    key={star}
                                    className={`star-btn ${ratingData.rating >= star ? 'active' : ''}`}
                                    onClick={() => setRatingData({...ratingData, rating: star})}
                                >
                                    ★
                                </button>
                            ))}
                        </div>

                        <div className="form-group">
                            <label>Review (Optional)</label>
                            <textarea
                                value={ratingData.review}
                                onChange={(e) => setRatingData({...ratingData, review: e.target.value})}
                                placeholder="Tell others about your experience..."
                                rows="3"
                            />
                        </div>

                        <div className="modal-actions">
                            <button 
                                className="btn-cancel"
                                onClick={() => {
                                    setShowRatingModal(false);
                                    setRatingData({ rating: 5, review: '' });
                                    setCurrentJobForRating(null);
                                }}
                            >
                                Skip for now
                            </button>
                            <button 
                                className="btn-submit"
                                onClick={handleCompleteJob}
                            >
                                Submit Rating & Complete
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default ClientDashboard;
